586		private getBroadCategoryNames({
587			categories,
588			allCategories,
589		}: {
590			styleId?: number;
591			categories: MMSStyleToProcess['categories'];
592			allCategories: MMSAllStyleCategory[];
593		}): string[] {
594			const activeCategories = categories
595				.map((cat) => {
596					const fullCategory = allCategories.find((c) => c._id === cat.parent_id);
597					if (fullCategory) {
598						cat['parent'] = fullCategory;
599					}
600					return cat;
601				})
602				.filter((cat) => cat.active);
603	
604			const allParents = activeCategories
605				.map((category) => category['parent'] ?? { ...category, _id: category.id })
606				.filter(Boolean) as MMSAllStyleCategory[];
607	
608			const uniqueParents = allParents.reduce<MMSAllStyleCategory[]>((acc, parent) => {
609				if (TAXONOMY_CAT_IDS.includes(parent._id)) {
610					return acc;
611				}
612	
613				if (!acc.some((p) => p._id === parent._id)) {
614					acc.push(parent);
615				}
616	
617				return acc;
618			}, []);
619	
620			const names = uniqueParents
621				.map((parent) => parent['name'])
622				.filter((name) => name && !EXCLUDED_CAT_NAMES.includes(name as string)) as string[];
623	
624			return [...new Set(names)];
625		}
