627		private getStylesSubcategories({
628			categories,
629			allCategories,
630		}: {
631			categories: MMSStyleToProcess['categories'];
632			allCategories: MMSAllStyleCategory[];
633		}): string[] {
634			const activeCategories = categories.filter((cat) => cat.active && cat.parent_id);
635	
636			const childCategories: string[] = [];
637	
638			for (const category of activeCategories) {
639				const hasChildren = allCategories.some((cat) => cat['parent_id'] === category.id);
640	
641				if (!hasChildren && category.name) {
642					childCategories.push(category.name);
643				}
644			}
645	
646			return [...new Set(childCategories)];
647		}
