653		private calculateLink({
654			style,
655			allCategories,
656		}: {
657			style: MMSStyleToProcess;
658			allCategories: MMSAllStyleCategory[];
659		}): Breadcrumb | null {
660			function urlFriendly(str: string): string {
661				return str
662					.toLowerCase()
663					.replace(/&reg;/g, '®')
664					.replace(/\//g, '-')
665					.replace(/\s+/g, '-')
666					.replace(/[^\+\-0-9_a-z]/g, '')
667					.replace(/^-+|-+$/g, '')
668					.replace(/-+/g, '-');
669			}
670	
671			const primaryCategory = style.primary_category;
672	
673			if (!primaryCategory) {
674				return null;
675			}
676	
677			const primaryCatParent = allCategories.find(
678				(cat) => cat._id === primaryCategory.parent_id,
679			);
680	
681			const primaryCatParentName = primaryCatParent?.['name'] as string;
682			const categoryName = primaryCategory.name;
683	
684			const firstPartLink = !primaryCatParent
685				? '/products'
686				: `/products/${urlFriendly(primaryCatParentName)}`;
687	
688			const path = `${firstPartLink}/${urlFriendly(categoryName)}/${urlFriendly(style.name)}/${style.id}`;
689	
690			return {
691				name: style.name,
692				path: path,
693			};
694		}
