701		private extractCategoriesWithParents({
702			categoryIds,
703			allCategories,
704		}: {
705			categoryIds: number[];
706			allCategories: MMSAllStyleCategory[];
707		}): number[] {
708			const allCategoryIds = new Set<number>();
709	
710			for (const categoryId of categoryIds) {
711				allCategoryIds.add(categoryId);
712	
713				const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
714				for (const parentId of parentIds) {
715					allCategoryIds.add(parentId);
716				}
717			}
718	
719			return Array.from(allCategoryIds).sort((a, b) => a - b);
720		}
