722		private getAllParentCategoryIds({
723			categoryId,
724			allCategories,
725		}: {
726			categoryId: number;
727			allCategories: MMSAllStyleCategory[];
728		}): number[] {
729			const parents: number[] = [];
730			const category = allCategories.find((cat) => cat._id === categoryId);
731	
732			if (!category?.['parent_id']) {
733				return parents;
734			}
735	
736			let currentParentId = category['parent_id'] as number;
737	
738			while (currentParentId) {
739				parents.push(currentParentId);
740	
741				const parentCategory = allCategories.find((cat) => cat._id === currentParentId);
742				if (!parentCategory?.['parent_id']) {
743					break;
744				}
745	
746				currentParentId = parentCategory['parent_id'] as number;
747			}
748	
749			return parents;
750		}
