752		private getRootCategoryId({
753			style,
754			allCategories,
755		}: {
756			style: MMSStyleToProcess;
757			allCategories: MMSAllStyleCategory[];
758		}): number | null {
759			if (!style.primary_category) {
760				return null;
761			}
762	
763			const primaryCategory = allCategories.find(
764				(cat) => cat._id === style.primary_category_id,
765			);
766			if (!primaryCategory) {
767				return null;
768			}
769	
770			let currentCategory = primaryCategory;
771			while (currentCategory['parent_id']) {
772				const parentCategory = allCategories.find(
773					(cat) => cat._id === currentCategory['parent_id'],
774				);
775				if (!parentCategory) break;
776				currentCategory = parentCategory;
777			}
778	
779			return !currentCategory['parent_id'] ? currentCategory._id : null;
780		}
